    private final String displayName;
    private final String color;
    private final boolean special;
    private final String texture;
    private final String signature;
    private final Perk[] allPerks;

    SkyBlockMayor(String displayName, String color, boolean special, String texture, String signature, Perk[] allPerks) {
        this.displayName = displayName;
        this.color = color;
        this.special = special;
        this.texture = texture;
        this.signature = signature;
        this.allPerks = allPerks;
    }

    public String getColoredName() {
        return color + displayName;
    }

    public static List<SkyBlockMayor> getRegularMayors() {
        return Arrays.stream(values()).filter(m -> !m.special).toList();
    }

    public static List<SkyBlockMayor> getSpecialMayors() {
        return Arrays.stream(values()).filter(m -> m.special).toList();
    }

